#include<bits/stdc++.h>
using namespace std;
int main(){
    deque<int> d[1000005];
    int q;
    cin>>q;
    for(int i=1;i<=q;i++){
            string qq;
        int a,b;
        cin>>qq>>a;
        if(qq=="push_front"||qq=="push_back"){
            cin>>b;
            if(qq=="push_front"){
                d[a].push_front(b);
            }else{
                d[a].push_back(b);
            }
        }else{
            if(qq=="pop_back"){
                d[a].pop_back();
            }if(qq=="pop_front"){
                d[a].pop_front();
            }if(qq=="size"){
                cout<<d[a].size()<<"\n";
            }if(qq=="front"){
                cout<<d[a].front()<<"\n";
            }if(qq=="back"){
                cout<<d[a].back()<<"\n";
            }
        }
    }
    return 0;
}
